def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("source")
    parser.add_argument("output")
    args = parser.parse_args()

    doc = Document(args.source)
    configure_document(doc)

    for heading, paragraphs in SECTION_TEXT.items():
        insert_block_after_heading(doc, heading, paragraphs)

    cursor = doc.paragraphs[-1]
    for text, is_heading in CONCLUSION_TEXT:
        paragraph = insert_paragraph_after(cursor, text)
        if is_heading:
            format_heading(paragraph)
        else:
            format_body(paragraph)
        cursor = paragraph

    doc.save(args.output)
    print(args.output)


def configure_document(doc):
    for section in doc.sections:
        section.top_margin = Cm(2)
        section.bottom_margin = Cm(2)
        section.left_margin = Cm(3)
        section.right_margin = Cm(1.5)

    normal = doc.styles["Normal"]
    normal.font.name = "Times New Roman"
    normal.font.size = Pt(14)


def insert_block_after_heading(doc, heading_text, paragraphs):
    heading = next((p for p in doc.paragraphs if p.text.strip() == heading_text), None)
    if heading is None:
        raise RuntimeError(f"Heading not found: {heading_text}")

    format_heading(heading)
    cursor = heading
    for text in paragraphs:
        paragraph = insert_paragraph_after(cursor, text)
        format_body(paragraph)
        cursor = paragraph


def insert_paragraph_after(paragraph, text=""):
    new_p = OxmlElement("w:p")
    paragraph._p.addnext(new_p)
    new_paragraph = paragraph._parent.add_paragraph()
    new_paragraph._p = new_p
    new_paragraph._element = new_p
    if text:
        new_paragraph.add_run(text)
    return new_paragraph


def format_body(paragraph):
    paragraph.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    paragraph.paragraph_format.first_line_indent = Cm(1.25)
    paragraph.paragraph_format.line_spacing = 1.5
    paragraph.paragraph_format.space_after = Pt(0)
    for run in paragraph.runs:
        run.font.name = "Times New Roman"
        run.font.size = Pt(14)


def format_heading(paragraph):
    paragraph.alignment = WD_ALIGN_PARAGRAPH.CENTER
    paragraph.paragraph_format.first_line_indent = Cm(0)
    paragraph.paragraph_format.line_spacing = 1.5
    paragraph.paragraph_format.space_before = Pt(12)
    paragraph.paragraph_format.space_after = Pt(6)
    for run in paragraph.runs:
        run.bold = True
        run.font.name = "Times New Roman"
        run.font.size = Pt(14)


if __name__ == "__main__":
    main()
